func TestShouldSkipAutoRefreshCommand_WalksAncestors(t *testing.T) {
	root := &cobra.Command{Use: "superhuman-pp-cli"}
	syncCmd := &cobra.Command{Use: "sync"}
	child := &cobra.Command{Use: "cache"}
	syncCmd.AddCommand(child)
	root.AddCommand(syncCmd)

	if !shouldSkipAutoRefreshCommand(child) {
		t.Fatalf("sync child should skip auto-refresh")
	}
	threads := &cobra.Command{Use: "threads"}
	list := &cobra.Command{Use: "list"}
	threads.AddCommand(list)
	root.AddCommand(threads)
	if shouldSkipAutoRefreshCommand(list) {
		t.Fatalf("threads list should auto-refresh")
	}
}

func TestAutoRefreshOptOutPrecedence(t *testing.T) {
	t.Setenv(autoRefreshEnvVar, "1")
	flags := &rootFlags{}
	root := &cobra.Command{Use: "superhuman-pp-cli"}
	root.PersistentFlags().BoolVar(&flags.noRefresh, "no-refresh", false, "")
	child := &cobra.Command{Use: "threads"}
	root.AddCommand(child)

	reason, skip := autoRefreshSkipReason(child, flags)
	if !skip || reason != "env" {
		t.Fatalf("env skip = %v/%q, want true/env", skip, reason)
	}
	if err := root.PersistentFlags().Set("no-refresh", "false"); err != nil {
		t.Fatalf("set no-refresh=false: %v", err)
	}
	reason, skip = autoRefreshSkipReason(child, flags)
	if skip || reason != "" {
		t.Fatalf("explicit --no-refresh=false should override env, got skip=%v reason=%q", skip, reason)
	}
	if err := root.PersistentFlags().Set("no-refresh", "true"); err != nil {
		t.Fatalf("set no-refresh=true: %v", err)
	}
	reason, skip = autoRefreshSkipReason(child, flags)
	if !skip || reason != "flag" {
		t.Fatalf("flag skip = %v/%q, want true/flag", skip, reason)
	}
}

